const b = $json.body || $json;
const req = ['first_name', 'last_name', 'email'];
for (const k of req) {
  if (!b[k]) throw new Error('Missing ' + k);
}
const clean = (value) => String(value || '').trim();
const record = {
  timestamp: new Date().toISOString(),
  status: 'New Request',
  lead_stage: 'New',
  first_name: clean(b.first_name),
  last_name: clean(b.last_name),
  email: clean(b.email),
  phone: clean(b.phone),
  vehicle: clean(b.vehicle),
  requested_service: clean(b.requested_service || b.service),
  source_site: clean(b.source_site),
  consent_to_contact: Boolean(b.consent_to_contact),
  notes: clean(b.notes || b.message),
};
const fullName = `${record.first_name} ${record.last_name}`.trim();
const vehicleLabel = record.vehicle || 'Vehicle TBD';
const line = JSON.stringify(record) + '\n';
const followUpStart = new Date(Date.now() + 24 * 60 * 60 * 1000);
followUpStart.setHours(10, 0, 0, 0);
const followUpEnd = new Date(followUpStart.getTime() + 30 * 60 * 1000);
const details = [
  `Name: ${fullName}`,
  `Email: ${record.email}`,
  `Phone: ${record.phone || 'Not provided'}`,
  `Vehicle: ${vehicleLabel}`,
  `Requested service: ${record.requested_service || 'Not provided'}`,
  `Source: ${record.source_site || 'Not provided'}`,
  `Consent to contact: ${record.consent_to_contact ? 'Yes' : 'No'}`,
  `Notes: ${record.notes || 'None'}`,
].join('\n');
const sender = 'crew@thegtcollective.com';
const notifyTo = 'crew@thegtcollective.com';
function b64url(input) {
  return Buffer.from(input, 'utf8').toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/g, '');
}
const internalSubject = `New GT service request - ${fullName || record.email} - ${vehicleLabel}`;
const customerSubject = 'Your GT Collective request has been received';
const customerBody = `Hi ${record.first_name || 'there'},

Thanks for reaching out to The Grand Tour Collective. We received your request and our team will review the vehicle details, requested service, and schedule availability.

This message confirms that your request was submitted successfully. It is not yet a confirmed appointment or final quote.

If we need anything else, we'll follow up at this email address or the phone number you provided.

Best,
The Grand Tour Collective
crew@thegtcollective.com`;
const calendarEventBody = {
  summary: `Verify GT request - ${fullName || record.email}`,
  description: details,
  start: { dateTime: followUpStart.toISOString(), timeZone: 'America/New_York' },
  end: { dateTime: followUpEnd.toISOString(), timeZone: 'America/New_York' },
  attendees: [{ email: notifyTo }],
};
const driveFolderBody = {
  name: `Lead - ${fullName || record.email} - ${vehicleLabel}`.replace(/[\\/:*?"<>|]/g, '-'),
  mimeType: 'application/vnd.google-apps.folder',
  parents: ['1Aae_1OQstLhBlmvv_yJiX1yM4r6XqsH0'],
};
return [{
  json: {
    ...record,
    fullName,
    vehicleLabel,
    details,
    sender,
    notifyTo,
    internalSubject,
    customerSubject,
    customerBody,
    calendarEventBody,
    driveFolderBody,
    calendarEventJson: JSON.stringify(calendarEventBody),
    internalEmail: { to: notifyTo, subject: internalSubject, message: details },
    customerEmail: { to: record.email, subject: customerSubject, message: customerBody },
    internalEmailBody: { raw: b64url(`From: ${sender}\r\nTo: ${notifyTo}\r\nSubject: ${internalSubject}\r\nContent-Type: text/plain; charset=UTF-8\r\n\r\n${details}`) },
    customerEmailBody: { raw: b64url(`From: ${sender}\r\nTo: ${record.email}\r\nSubject: ${customerSubject}\r\nContent-Type: text/plain; charset=UTF-8\r\n\r\n${customerBody}`) },
  },
  binary: {
    data: {
      data: Buffer.from(line).toString('base64'),
      mimeType: 'application/jsonl',
      fileName: 'service-requests.jsonl',
    },
  },
}];

const lead = $('Validate + Build Google Payloads').item.json;
const drive = $('Create Drive Lead Folder').item.json;
const calendar = $('Create Calendar Verification Event').item.json;
const prompt = [
  lead.details,
  drive?.id ? 'Drive folder: https://drive.google.com/drive/folders/' + drive.id : 'Drive folder: unavailable',
  calendar?.htmlLink ? 'Calendar event: ' + calendar.htmlLink : 'Calendar event: unavailable',
].join('\n');
const script = "const prompt=Buffer.from(process.argv[1],'base64').toString('utf8'); const base=(process.env.LOCAL_AI_BASE_URL||'http://host.docker.internal:1234/v1').replace(/\\/$/,''); const model=process.env.LOCAL_AI_MODEL||'local-model'; fetch(base + '/chat/completions',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({model,messages:[{role:'system',content:'You write concise internal lead briefs for an automotive service and collecting business. Return plain text only. Include service category, urgency, missing info, suggested first response, and estimate-prep checklist.'},{role:'user',content:prompt}],temperature:0.2,stream:false})}).then(async r=>{const t=await r.text(); if(!r.ok){console.log(JSON.stringify({error:t,status:r.status})); return;} console.log(t);}).catch(e=>{console.log(JSON.stringify({error:e.message}));});";
return [{ json: { localAiCommand: 'node -e ' + JSON.stringify(script) + ' ' + Buffer.from(prompt).toString('base64') } }];
